var countKDifference = function(nums, k) {
    const cnt = new Map();
    for (const v of nums) cnt.set(v, (cnt.get(v) || 0) + 1);
    let total = 0;
    for (const [v, c] of cnt) {
        total += c * (cnt.get(v + k) || 0);
    }
    return total;
